// Enrich lead and determine the best Apollo sequence by industry
const items = $input.all();
const webhookBody = $('Webhook Trigger').item.json.body || {};

// ===== REPLACE THESE WITH YOUR ACTUAL APOLLO SEQUENCE IDS =====
const INDUSTRY_SEQUENCE_MAP = {
  'financial':      'SEQ_ID_FINANCIAL',
  'banking':        'SEQ_ID_FINANCIAL',
  'insurance':      'SEQ_ID_FINANCIAL',
  'fintech':        'SEQ_ID_FINANCIAL',
  'healthcare':     'SEQ_ID_HEALTHCARE',
  'medical':        'SEQ_ID_HEALTHCARE',
  'pharma':         'SEQ_ID_HEALTHCARE',
  'biotech':        'SEQ_ID_HEALTHCARE',
  'hospital':       'SEQ_ID_HEALTHCARE',
  'retail':         'SEQ_ID_RETAIL',
  'ecommerce':      'SEQ_ID_RETAIL',
  'e-commerce':     'SEQ_ID_RETAIL',
  'consumer':       'SEQ_ID_RETAIL',
  'manufacturing':  'SEQ_ID_MANUFACTURING',
  'industrial':     'SEQ_ID_MANUFACTURING',
  'automotive':     'SEQ_ID_MANUFACTURING',
  'technology':     'SEQ_ID_TECH',
  'software':       'SEQ_ID_TECH',
  'saas':           'SEQ_ID_TECH',
  'information technology': 'SEQ_ID_TECH',
  'energy':         'SEQ_ID_ENERGY',
  'oil':            'SEQ_ID_ENERGY',
  'utilities':      'SEQ_ID_ENERGY',
  'renewable':      'SEQ_ID_ENERGY',
  'education':      'SEQ_ID_EDUCATION',
  'university':     'SEQ_ID_EDUCATION',
  'school':         'SEQ_ID_EDUCATION',
  'legal':          'SEQ_ID_LEGAL',
  'law':            'SEQ_ID_LEGAL',
  'real estate':    'SEQ_ID_REALESTATE',
  'property':       'SEQ_ID_REALESTATE',
  'construction':   'SEQ_ID_REALESTATE',
  'logistics':      'SEQ_ID_LOGISTICS',
  'transportation': 'SEQ_ID_LOGISTICS',
  'shipping':       'SEQ_ID_LOGISTICS',
  'supply chain':   'SEQ_ID_LOGISTICS',
  'telecom':        'SEQ_ID_TELECOM',
  'telecommunications': 'SEQ_ID_TELECOM'
};

const DEFAULT_SEQUENCE = 'SEQ_ID_GENERAL';

return items.map(item => {
  const d = item.json;
  const industry = (d.industry || '').toLowerCase();

  let sequenceId = DEFAULT_SEQUENCE;
  let matchedIndustry = 'General';
  for (const [keyword, seqId] of Object.entries(INDUSTRY_SEQUENCE_MAP)) {
    if (industry.includes(keyword)) {
      sequenceId = seqId;
      matchedIndustry = keyword;
      break;
    }
  }

  const employees = parseInt(d.num_employees) || 0;
  let companySize = '';
  if (employees > 1000) companySize = 'enterprise';
  else if (employees > 200) companySize = 'mid-market';
  else if (employees > 50) companySize = 'growing';
  else companySize = 'emerging';

  // Use company_description from DB or from webhook body (pre-built by frontend)
  const companyDescription = d.company_description || webhookBody.company_description || '';
  // Use sector from webhook body or compute it
  const sector = webhookBody.sector || matchedIndustry;

  return {
    json: {
      lead_id: d.id,
      first_name: d.first_name || '',
      last_name: d.last_name || '',
      full_name: `${d.first_name || ''} ${d.last_name || ''}`.trim(),
      title: d.title || '',
      company_name: d.company_name || '',
      email: d.email || '',
      email_status: d.email_status || '',
      industry: d.industry || '',
      matched_industry: matchedIndustry,
      sector: sector,
      company_description: companyDescription,
      num_employees: d.num_employees || '',
      seniority: d.seniority || '',
      city: d.city || '',
      state: d.state || '',
      country: d.country || '',
      person_linkedin_url: d.person_linkedin_url || '',
      website: d.website || '',
      annual_revenue: d.annual_revenue || '',
      technologies: d.technologies || '',
      keywords: d.keywords || '',
      primary_intent_topic: d.primary_intent_topic || '',
      primary_intent_score: d.primary_intent_score || '',
      company_size_category: companySize,
      apollo_contact_id: d.apollo_contact_id || '',
      sequence_id: sequenceId,
      email_attempts: (d.email_attempts || 0) + 1,
      source_table: webhookBody.source_table || 'apollo_leads'
    }
  };
});

// Check if contact already exists in Apollo (people/match returns person directly)
const matchResult = $input.first().json;
const leadData = $('Enrich & Map Industry Sequence').item.json;

let apolloContactId = leadData.apollo_contact_id;
let contactExists = false;

// people/match returns { person: {...} } or { person: null }
if (matchResult.person && matchResult.person.id) {
  apolloContactId = matchResult.person.id;
  contactExists = true;
} else if (matchResult.contacts && matchResult.contacts.length > 0) {
  // Fallback for contacts/search response format
  apolloContactId = matchResult.contacts[0].id;
  contactExists = true;
}

return [{
  json: {
    ...leadData,
    apollo_contact_id: apolloContactId,
    contact_exists: contactExists
  }
}];

// Extract the new contact ID
const created = $input.first().json;
const prevData = $('Check Apollo Contact').item.json;

return [{
  json: {
    ...prevData,
    apollo_contact_id: created.contact?.id || created.id || prevData.apollo_contact_id
  }
}];

// Build rich company description from Apollo org enrichment + local data
const orgData = $input.first().json;
const leadData = $('Check Apollo Contact').item.json;
const org = orgData.organization || orgData || {};

const parts = [];

// Company name + short description from Apollo
const name = org.name || leadData.company_name || '';
const shortDesc = org.short_description || org.seo_description || '';
if (name) parts.push(name);
if (shortDesc) parts.push(shortDesc);

// Industry + sector
const industry = org.industry || leadData.industry || '';
if (industry && !shortDesc.toLowerCase().includes(industry.toLowerCase())) {
  parts.push('Industry: ' + industry);
}

// Location
const hqCity = org.city || leadData.city || '';
const hqState = org.state || leadData.state || '';
const hqCountry = org.country || leadData.country || '';
const loc = [hqCity, hqState, hqCountry].filter(Boolean).join(', ');
if (loc) parts.push('HQ: ' + loc);

// Size + Revenue
const employees = org.estimated_num_employees || leadData.num_employees || '';
if (employees) parts.push(employees + ' employees');
const revenue = org.annual_revenue_printed || leadData.annual_revenue || '';
if (revenue) parts.push('Revenue: ' + revenue);

// Founded
if (org.founded_year) parts.push('Founded: ' + org.founded_year);

// Technologies (from Apollo or local)
const techs = (org.current_technologies || []).slice(0, 6);
const localTechs = (leadData.technologies || '').split(',').map(t => t.trim()).filter(Boolean).slice(0, 6);
const allTechs = techs.length > 0 ? techs.map(t => t.name || t) : localTechs;
if (allTechs.length > 0) parts.push('Tech: ' + allTechs.join(', '));

// Keywords from local data
const keywords = (leadData.keywords || '').split(',').map(k => k.trim()).filter(Boolean).slice(0, 5);
if (keywords.length > 0) parts.push('Focus: ' + keywords.join(', '));

const companyDescription = parts.join('. ').replace(/\.\.+/g, '.').trim();

return [{
  json: {
    ...leadData,
    company_description: companyDescription || leadData.company_description || '',
    apollo_org_id: org.id || '',
    apollo_org_name: org.name || ''
  }
}];
